from flask import Flask, request, jsonify
import tensorflow as tf
import pandas as pd
import numpy as np
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Conv2D, Flatten, MaxPooling2D
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def create_model(input_shape, num_classes):
    model = Sequential([
        Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
        MaxPooling2D((2, 2)),
        Flatten(),
        Dense(128, activation='relu'),
        Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])
    return model

def load_and_preprocess_data(file_path):
    data = pd.read_csv(file_path)
    images = data.iloc[:, 1:].values.reshape(-1, 28, 28, 1) / 255.0
    labels = data.iloc[:, 0].values
    return images, labels

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    filename = secure_filename(file.filename)
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(file_path)
    
    try:
        images, labels = load_and_preprocess_data(file_path)
        model = create_model((28, 28, 1), 10)
        model.fit(images, labels, epochs=5)
        return jsonify({'success': 'Model trained successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute_examples():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    filename = secure_filename(file.filename)
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    file.save(file_path)
    
    try:
        images, labels = load_and_preprocess_data(file_path)
        # Here we assume the model already exists and is loaded
        model = tf.keras.models.load_model('community_model.h5')
        model.fit(images, labels, epochs=5)
        model.save('community_model.h5')
        return jsonify({'success': 'Training examples contributed successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)